void Dice()
{
    static const UC ucDice[7] = {0x0F,0x01,0x02,0x03,0x06,0x07,0x0E};
    static UC DiceValue = 0;
    ucPort1  = ucDice[DiceValue];

    ne = bReadPin(2,4);
    if(ne != ae){
        if(ne == 0){
            if(ucFlagTM2 == 1){
                ucFlagTM2 = 0;
                DiceValue++;
                if(DiceValue > 6){
                    DiceValue = 1;
                }
            vWritePort(~ucPort1,1);
            }
        }
        if(ne == 1){
          ae = ne;
        }
    }

    vWritePort(~ucPort1,1);

}
